    static var featured: [MobileInterviewGuideSummary] {
        all.sorted { left, right in
            let leftScore = left.questionCount * 4 + left.stageCount * 2 + Int(left.difficulty ?? 0)
            let rightScore = right.questionCount * 4 + right.stageCount * 2 + Int(right.difficulty ?? 0)
            return leftScore == rightScore ? left.company < right.company : leftScore > rightScore
        }
    }

    /// Mirrors the first company cards shown on the web Interview Studio.
    /// The complete catalog is still available through search and categories.
    static var webFeatured: [MobileInterviewGuideSummary] {
        let slugs = [
            "sap", "figma", "scale-ai", "hashicorp", "mercury", "vercel",
            "alibaba-interview-guide", "okta-interview-guide", "spacex-interview-guide",
            "confluent-interview-guide", "openai", "wealthfront"
        ]
        let bySlug = Dictionary(uniqueKeysWithValues: all.map { ($0.slug, $0) })
        return slugs.compactMap { bySlug[$0] }
    }

    static func topicChips(for slug: String) -> [String] {
        featuredContent[slug]?.topics ?? []
    }

    static func tipCount(for slug: String) -> Int {
        featuredContent[slug]?.tips ?? 0
    }

